#define DEBUG_TYPE "vplan-verifier"

using namespace llvm;

/// Verify that \p VPBB has a valid def-use chain.
/// I.e., for each recipe R in \p VPBB, check that R's operands are defined
/// before R.
static bool verifyBlock(const VPBasicBlock *VPBB,
                        DenseMap<const VPRecipeBase *, unsigned> &RecipeNumbering,
                        DenseSet<const BasicBlock *> &WrappedIRBBs) {
  // First, number all recipes in the block in order.
  unsigned Cnt = 0;
  for (const VPRecipeBase &R : *VPBB)
    RecipeNumbering[&R] = Cnt++;

